// Get the currently selected Financial Year Week in the visual context
VAR CurrentWeek = SELECTEDVALUE('Date'[Financial Year Week Id])

// If a specific week is selected (row-level logic)
VAR WeekAvg =
    VAR DaysThisWeek =
        // Get all dates that belong to the selected week
        FILTER(
            ALL('Date'),
            'Date'[Financial Year Week Id] = CurrentWeek
        )

    VAR ValidDays =
        // From those days, keep only the ones where stock was available
        // Add both sales and stock columns to evaluate each day's condition
        FILTER(
            ADDCOLUMNS(
                DaysThisWeek,
                "Sales", CALCULATE([Retail Sales Quantity (Net Retail Physical Returns)]),
                "Stock", CALCULATE([Saleable Stock Units])
            ),
            [Stock] > 0
        )

    VAR TotalSales =
        // Sum the daily sales for those valid days
        SUMX(ValidDays, [Sales])

    VAR ActiveDays =
        // Count how many valid days had stock > 0
        COUNTROWS(ValidDays)

    // Return average daily sales for the selected week
    RETURN DIVIDE(TotalSales, ActiveDays)


// If no specific week is selected (i.e., Total Row logic)
VAR AllWeekAvgs =
    // Go through all available weeks in the model
    ADDCOLUMNS(
        VALUES('Date'[Financial Year Week Id]),
        "WeekAvg",
        VAR WeekId = 'Date'[Financial Year Week Id]

        VAR WeekDays =
            // Get all calendar dates for this particular week
            FILTER(
                ALL('Date'),
                'Date'[Financial Year Week Id] = WeekId
            )

        VAR ValidDays =
            // Keep only the days where stock > 0
            FILTER(
                ADDCOLUMNS(
                    WeekDays,
                    "Sales", CALCULATE([Retail Sales Quantity (Net Retail Physical Returns)]),
                    "Stock", CALCULATE([Saleable Stock Units])
                ),
                [Stock] > 0
            )

        VAR TotalSales =
            // Total sales across those valid days
            SUMX(ValidDays, [Sales])

        VAR ActiveDays =
            // Number of valid days in the week (stock > 0)
            COUNTROWS(ValidDays)

        // Return weekly average sales per valid day
        RETURN DIVIDE(TotalSales, ActiveDays)
    )

VAR ResultWhenTotal =
    // Compute the final total row value as the unweighted average
    // of all weekly averages (each week contributes equally)
    AVERAGEX(AllWeekAvgs, [WeekAvg])

// Return the correct value depending on the context (week row or total row)
RETURN
    IF(
        ISBLANK(CurrentWeek),
        ResultWhenTotal,  // Total row
        WeekAvg           // Row-level value
    )

