           IF( //if any column of the date table is selected
             ISFILTERED('Date'),
            CALCULATE(
            SUM( 'Daily Trade'[Stock Buy Value]),
            //we only want closing buy value, i.e. sunday's buy value
             'Date'[Calendar Day Of Week Id] = 7 ,
             // Tradeable stock only
                'Inventory Status'[Inventory Status Subgroup Id] = 3
                   ),
                   // if the date is not filtered, i.e. no selection on date table
                   CALCULATE( 
                    SUM( 'Daily Trade'[Stock Buy Value]),
                    'Date'[Calendar Day Of Week Id] = 7 ,
                    'Date'[Financial Year Week Id] = this_fin_week - 1,
                    'Inventory Status'[Inventory Status Subgroup Id] = 3
                   )
            )
 RETURN result

